#include <iostream>
#include <string>
#include <sstream>
#include <iomanip>
#include <algorithm>

// Assume Rectangle class is defined here or included

int main() {
    std::string line;
    while (std::getline(std::cin, line)) {
        std::stringstream ss(line);
        double w, h;
        char comma;
        if (!(ss >> w >> comma >> h)) {
            std::cout << "ERROR: Invalid input format." << std::endl;
            continue;
        }

        Rectangle rect;
        double area = rect.setDimensions(w, h).calculateArea();

        std::cout << std::fixed << std::setprecision(2) << area << std::endl;
    }
    return 0;
}
